"const fs = require('fs');
const readline = require('readline');

const logPath = 'C:/Users/paloptical/.gemini/antigravity/brain/f89774ed-f905-432d-8902-e9fb55f69e45/.system_generated/logs/transcript.jsonl';

const rl = readline.createInterface({
  input: fs.createReadStream(logPath),
  crlfDelay: Infinity
});

let lineCount = 0;
let matchCount = 0;

rl.on('line', (line) => {
  lineCount++;
  if (line.includes('App.tsx') && line.includes('PatientInfoForm') && line.includes('1: import')) {
    try {
      const data = JSON.parse(line);
      const text = data.content || '';
      if (text.includes('1: import')) {
        matchCount++;
        const filename = `app_tsx_step_${data.step_index || lineCount}.txt`;
        fs.writeFileSync(filename, text);
        console.log(`Saved matched content to ${filename} (step ${data.step_index})`);
      }
    } catch (e) {
      console.log(`Error parsing JSON on line ${lineCount}: ${e.message}`);
    }
  }
});

rl.on('close', () => {
  console.log(`Done. Found ${matchCount} matches.`);
});
"
